package org.apache.commons.csv;

import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrint_nullValue_formatNullStringNull() throws IOException {
        when(format.getNullString()).thenReturn(null);
        // Since nullString is null, strValue should be Constants.EMPTY
        // We need to spy printer to verify print(Object, CharSequence, int, int) is called with correct parameters
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.print(null);

        verify(format).getNullString();
        verify(spyPrinter).print(null, Constants.EMPTY, 0, Constants.EMPTY.length());
    }

    @Test
    void testPrint_nullValue_formatNullStringNotNull() throws IOException {
        final String nullStr = "NULL";
        when(format.getNullString()).thenReturn(nullStr);
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.print(null);

        verify(format).getNullString();
        verify(spyPrinter).print(null, nullStr, 0, nullStr.length());
    }

    @Test
    void testPrint_nonNullValue() throws IOException {
        String val = "abc";
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.print(val);

        verify(spyPrinter).print(val, val, 0, val.length());
    }

    @Test
    void testPrint_privatePrintMethod_invocation() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Use reflection to invoke private print(Object, CharSequence, int, int)
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        String val = "hello";
        printMethod.invoke(printer, val, val, 0, val.length());

        // No exception means success
    }

    @Test
    void testPrint_privatePrintMethod_nullObject() throws Exception {
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        // invoke with null object and empty string
        printMethod.invoke(printer, null, "", 0, 0);
    }

    @Test
    void testPrint_privatePrintMethod_emptyString() throws Exception {
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        printMethod.invoke(printer, "test", "", 0, 0);
    }
}
